<?php

namespace Database\Seeders;

use Illuminate\Database\Seeder;
use App\Models\Office;
use App\Models\GeospatialLandmark;
use Illuminate\Support\Facades\DB;

/**
 * GeospatialLandmarkSeeder
 *
 * Seeds geospatial_landmarks from FRESH_UPDATE.xlsx (1,047 landmarks).
 * Hierarchy: Region → Zone → Sector → Beat → Landmark
 * Zone mapping (offices_data.json IDs):
 *   Motorway North (zone_id=1), Motorway C-I (zone_id=2), Motorway C-II (zone_id=3)
 *   N5 North (zone_id=4),   N5 Central (zone_id=5), N5 South (zone_id=6)
 *   West (zone_id=7)
 *
 * Sector → Beat → Landmark data is 100% sourced from the Excel file.
 * Run OfficeSeeder BEFORE this seeder.
 */
class GeospatialLandmarkSeeder extends Seeder
{
    // ── Resolved office IDs (populated at runtime) ─────────────────
    private array $beatCache = [];

    public function run(): void
    {
        DB::disableQueryLog();

        // ── Pre-build beat lookup: "ZoneName|SectorName|BeatName" => office.id ──
        $this->buildBeatCache();

        $data = $this->getLandmarkData();

        $rows = [];
        $now  = now()->toDateTimeString();

        foreach ($data as $item) {
            $beatId = $this->resolveBeat(
                $item['zone'],
                $item['sector'],
                $item['beat']
            );

            if (! $beatId) {
                $this->command->warn(
                    "Beat not found: {$item['zone']} / {$item['sector']} / {$item['beat']}"
                );
                continue;
            }

            // Parse numeric KM (take first number from ranges like "95-97")
            $kmNumeric = $this->parseKm($item['km']);

            // Auto-generate agent prompt
            $prompt = $this->buildAgentPrompt($item);

            $rows[] = [
                'office_id'       => $beatId,
                'road_name'       => $item['road'],
                'bound_direction'  => $item['direction'],
                'km_marker'        => $item['km'],
                'km_numeric'       => $kmNumeric,
                'zone_name'        => $item['zone'],
                'sector_name'      => $item['sector'],
                'beat_name'        => $item['beat'],
                'location_name'    => $item['location'],
                'nearby_cities'    => $item['cities'],
                'fuel_station'     => $item['fuel'],
                'agent_prompt'     => $prompt,
                'contact_numbers'  => $item['contacts'] ?: null,
                'created_at'       => $now,
                'updated_at'       => $now,
            ];
        }

        // Chunk-insert for performance
        foreach (array_chunk($rows, 200) as $chunk) {
            GeospatialLandmark::upsert(
                $chunk,
                ['office_id', 'road_name', 'km_marker', 'location_name'],
                ['bound_direction', 'km_numeric', 'zone_name', 'sector_name',
                 'beat_name', 'nearby_cities', 'fuel_station', 'agent_prompt',
                 'contact_numbers', 'updated_at']
            );
        }

        $this->command->info(
            "GeospatialLandmarks seeded: " . count($rows) . " records across 7 zones."
        );
    }

    // ─────────────────────────────────────────────────────────────────
    //  Beat cache builder
    // ─────────────────────────────────────────────────────────────────
    private function buildBeatCache(): void
    {
        // Load all beat offices with their parent chain
        $beats = Office::where('type', 'beat')
                       ->with(['parent' => fn($q) => $q->with('parent')])
                       ->get();

        foreach ($beats as $beat) {
            $sector = $beat->parent;         // Sector office
            $zone   = $sector?->parent;      // Zone office

            if (! $sector || ! $zone) continue;

            $key = $this->cacheKey($zone->name, $sector->name, $beat->name);
            $this->beatCache[$key] = $beat->id;
        }
    }

    private function cacheKey(string $zone, string $sector, string $beat): string
    {
        return mb_strtolower(trim($zone) . '|' . trim($sector) . '|' . trim($beat));
    }

    private function normalizeBeatName(string $beat): string
    {
        // Convert "Beat 01", "Beat 1", "Beat-1" to "Beat-01"
        if (preg_match('/Beat[- ]?(\d+)/i', $beat, $matches)) {
            return 'Beat-' . str_pad($matches[1], 2, '0', STR_PAD_LEFT);
        }
        
        // Handle Roman Numerals if any (e.g. Beat-I -> Beat-01)
        $romans = ['I' => '01', 'II' => '02', 'III' => '03', 'IV' => '04', 'V' => '05'];
        foreach ($romans as $roman => $num) {
            if (str_ends_with(strtoupper($beat), "-$roman") || str_ends_with(strtoupper($beat), " $roman")) {
                return 'Beat-' . $num;
            }
        }

        return $beat;
    }

    private function resolveBeat(string $zone, string $sector, string $beat): ?int
    {
        // 1. Try direct match with normalization
        $key = $this->cacheKey($zone, $sector, $beat);
        if (isset($this->beatCache[$key])) {
            return $this->beatCache[$key];
        }

        // 2. Try normalized beat name (e.g. Beat-1 -> Beat-01, Beat 13 -> Beat-13)
        $normBeat = $this->normalizeBeatName($beat);
        $key = $this->cacheKey($zone, $sector, $normBeat);
        if (isset($this->beatCache[$key])) {
            return $this->beatCache[$key];
        }

        // 3. Fallback: search by beat name + sector name (ignore zone if needed, or fuzzy)
        foreach ($this->beatCache as $k => $id) {
            // $k is "zone|sector|beat"
            $parts = explode('|', $k);
            if (count($parts) < 3) continue;

            $cZone = $parts[0];
            $cSector = $parts[1];
            $cBeat = $parts[2];

            if ($this->normalizeBeatName($cSector) === $this->normalizeBeatName($sector) && 
                $this->normalizeBeatName($cBeat) === $this->normalizeBeatName($beat)) {
                return $id;
            }
        }

        return null;
    }

    private function parseKm(?string $km): ?float
    {
        if (blank($km)) return null;
        // Extract first numeric part (handles "95-97", "24-N", "355-354(S)", "46 SB")
        preg_match('/([\d]+(?:\.\d+)?)/', $km, $m);
        return isset($m[1]) ? (float) $m[1] : null;
    }

    private function buildAgentPrompt(array $item): string
    {
        $loc     = $item['location'];
        $road    = $item['road'];
        $km      = $item['km'];
        $cities  = $item['cities'];
        $fuel    = $item['fuel'];

        $prompt  = "Ask the commuter if they recently passed {$loc}";
        if ($km) {
            $prompt .= " at KM {$km} on {$road}";
        }
        if ($cities) {
            $prompt .= ". Nearby: {$cities}";
        }
        if ($fuel) {
            $prompt .= ". Fuel available {$fuel} from this point";
        }
        $prompt .= ".";

        return $prompt;
    }

